import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as s,e as a}from"./app-48200f17.js";const r={},d=a(`<h1 id="代码风格的理解" tabindex="-1"><a class="header-anchor" href="#代码风格的理解" aria-hidden="true">#</a> 代码风格的理解</h1><p>个人感觉写代码本身这件事就是类似于构建房子，代码的功能实现就是房子的可居住能力，不同的代码实现都可以实现可居住的功能，但是居住功能不是房子的首要属性吗？不同的代码对应着不同功能的房子，打个比方：前端代码对应着商业楼，<code>python</code>对应着住宅楼，<code>java</code>代码代表着工业园。不同的代码风格可能代表着不同的建筑风格，很差的代码风格对应着木板房，好的代码可能就是高大的 <code>CBD</code>大楼。</p><h2 id="第一步-打地基——代码模块设计" tabindex="-1"><a class="header-anchor" href="#第一步-打地基——代码模块设计" aria-hidden="true">#</a> 第一步：打地基——代码模块设计</h2><p><strong>建造房子的第一步是打地基，地基也就代表着房子的实现的高度和建筑面积。同样代码的模块设计也就代表着代码的实现功能，以及实现功能的复杂度和可维护度。</strong></p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>from flask import Flask

app = Flask(__name__)

@app.route(&#39;/&#39;)
def hello():
    return &#39;Welcome to My Watchlist!&#39;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>例如以上的单文件也是一个后端项目，但是单文件代码如果实现复杂功能就会相当的麻烦，也是不方便维护的</strong></p><h2 id="第二步-建房子——类的构建" tabindex="-1"><a class="header-anchor" href="#第二步-建房子——类的构建" aria-hidden="true">#</a> 第二步：建房子——类的构建</h2><p>** **建筑中很重要的一步就是房间的建造，房间是作为建筑物中的主体实现功能。同样 <code>classs</code>在于代码中也是特别重要的功能，是大部分代码中主要功能的实现主体。</p><p>** **房子是有不同的功能属性的，有厨房，客厅等，类其实也是可以分为不同功能的，一般大家会分为这个是实现 A 功能，另外一个是实现 B 功能，但是我想从更加抽象的角度分为以下两类（这是站在后端的角度）</p><ul><li><strong>模型类——数据库模型</strong></li><li><strong>逻辑类——逻辑处理</strong></li></ul><hr><h2 id="第三步-装修——函数的编写" tabindex="-1"><a class="header-anchor" href="#第三步-装修——函数的编写" aria-hidden="true">#</a> 第三步：装修——函数的编写</h2><ul><li><strong>家具——函数</strong><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>房间中的家具我的理解就是类中函数，类是功能的聚合。其实功能的具体实现的是类中的函数进行实现的
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><strong>园区指引——变量名，注释</strong><br><strong>一个小区一定会有几号楼那个房间，这个对应代码的就是变量名。</strong><br><strong>如果是园区的话那也会有园区介绍，这个就是注释的作用，可以让我们快速了解代码的功能</strong></li><li><strong>消防通道——异常处理</strong></li><li><strong>监控系统——日志处理</strong></li></ul><h2 id="第四步-验房——测试" tabindex="-1"><a class="header-anchor" href="#第四步-验房——测试" aria-hidden="true">#</a> 第四步：验房——测试</h2><p><strong>当房子建造完成之后，验房是我们很重的一步，不能满心欢喜的去验房但是到头来房子的质量不达标，连墙都是不直的这要怎么居住呢？</strong></p><p><strong>对于代码也是一样的道理，写的觉得自己的代码写的很好但是一运行起来全是 bug 也是不行的，因此测试是开发中很重要的一步。代码中的每一个功能都需要进行测试，也要对于代码的性能进行测试。</strong></p><h2 id="第五步-入住——devops自动化部署" tabindex="-1"><a class="header-anchor" href="#第五步-入住——devops自动化部署" aria-hidden="true">#</a> 第五步：入住——<code>devops</code>自动化部署</h2><p><strong>软件开发完成进行部署，也就是开始正式使用，是不是和入住类似？</strong></p><p><code>devops</code>在软件中一般指的是代码的自动化部署。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>devops是一种方法，也是一种工具，还是一种思想
来自官方：
DevOps是一组过程、方法与系统的统称，用于促进开发、技术运营和质量保障（QA）部门之间的沟通、协作与整合。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>因此整个代码比成一栋楼，那么这个重要性就不言而喻了，楼的质量不好对整个生命安全都会有影响，代码的质量不好可能会造成以下几个方面的影响</strong></p><ul><li><strong>代码 bug，项目上线之后可能会造成生产事故</strong></li><li><strong>代码难以维护，新进同事难以快速了解项目，过久的学习时间，也会造成</strong> <code>屎山</code>的堆积</li></ul>`,22),i=[d];function t(o,l){return n(),s("div",null,i)}const u=e(r,[["render",t],["__file","代码风格的理解.html.vue"]]);export{u as default};
